import{_ as o,c as l,o as i,ae as a}from"./chunks/framework.Bw7rlmih.js";const h=JSON.parse('{"title":"00: Control Plane Core","description":"","frontmatter":{},"headers":[],"relativePath":"control-plane/00-control-plane-core.md","filePath":"control-plane/00-control-plane-core.md"}'),c={name:"control-plane/00-control-plane-core.md"};function t(n,e,d,r,s,u){return i(),l("div",null,e[0]||(e[0]=[a('<h1 id="_00-control-plane-core" tabindex="-1">00: Control Plane Core <a class="header-anchor" href="#_00-control-plane-core" aria-label="Permalink to &quot;00: Control Plane Core&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This document defines the core model and behavior of the Konfigo control plane.</p><p>It turns Konfigo from a local-only processor into a centralized system that can:</p><ul><li>store and version schemas, templates, values, files, and policies</li><li>resolve and execute bundle-based runs remotely</li><li>enforce immutable pinning and protected promotions</li><li>provide provenance and auditability</li></ul><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ul><li>Centralize configuration assets and execution intent.</li><li>Keep object versions immutable and reproducible.</li><li>Support controlled promotion between environments.</li><li>Make all decisions auditable.</li></ul><h2 id="non-goals" tabindex="-1">Non-Goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-Goals&quot;">​</a></h2><ul><li>Runtime traffic filtering or API gateway policy enforcement.</li><li>Dynamic policy language redesign in this phase.</li></ul><h2 id="canonical-scope-model" tabindex="-1">Canonical Scope Model <a class="header-anchor" href="#canonical-scope-model" aria-label="Permalink to &quot;Canonical Scope Model&quot;">​</a></h2><p>Use a logical <code>scope</code> prefix format:</p><ul><li><code>team/app/env/service</code></li><li>Example: <code>platform/payments/prod/api</code></li></ul><p><code>scope</code> is used consistently for:</p><ul><li>storage paths</li><li>access control checks</li><li>event partitioning</li><li>drift scans</li><li>promotion policies</li></ul><h2 id="core-object-model" tabindex="-1">Core Object Model <a class="header-anchor" href="#core-object-model" aria-label="Permalink to &quot;Core Object Model&quot;">​</a></h2><h3 id="project" tabindex="-1">Project <a class="header-anchor" href="#project" aria-label="Permalink to &quot;Project&quot;">​</a></h3><p>Represents top-level ownership and lifecycle boundary.</p><p>Fields:</p><ul><li><code>projectId</code></li><li><code>name</code></li><li><code>description</code></li><li><code>ownerGroup</code></li><li><code>createdAt</code></li></ul><h3 id="environment" tabindex="-1">Environment <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;Environment&quot;">​</a></h3><p>Represents deployment stage constraints (<code>dev</code>, <code>stage</code>, <code>prod</code>, custom).</p><p>Fields:</p><ul><li><code>environmentId</code></li><li><code>projectId</code></li><li><code>name</code></li><li><code>isProtected</code></li><li><code>promotionPolicyRef</code></li></ul><h3 id="schema-version" tabindex="-1">Schema@version <a class="header-anchor" href="#schema-version" aria-label="Permalink to &quot;Schema@version&quot;">​</a></h3><p>Immutable schema specification.</p><p>Fields:</p><ul><li><code>schemaRef</code> (<code>schema:&lt;name&gt;:&lt;version&gt;</code>)</li><li><code>contentDigest</code></li><li><code>content</code></li><li><code>createdBy</code></li><li><code>createdAt</code></li></ul><h3 id="template-version" tabindex="-1">Template@version <a class="header-anchor" href="#template-version" aria-label="Permalink to &quot;Template@version&quot;">​</a></h3><p>Immutable template content.</p><p>Fields:</p><ul><li><code>templateRef</code> (<code>template:&lt;name&gt;:&lt;version&gt;</code>)</li><li><code>contentDigest</code></li><li><code>content</code></li><li><code>createdBy</code></li><li><code>createdAt</code></li></ul><h3 id="values-version" tabindex="-1">Values@version <a class="header-anchor" href="#values-version" aria-label="Permalink to &quot;Values@version&quot;">​</a></h3><p>Immutable values set bound to scope.</p><p>Fields:</p><ul><li><code>valuesRef</code> (<code>values:&lt;scope&gt;:&lt;version&gt;</code>)</li><li><code>scope</code></li><li><code>contentDigest</code></li><li><code>content</code></li><li><code>createdBy</code></li><li><code>createdAt</code></li></ul><h3 id="fileasset-version" tabindex="-1">FileAsset@version <a class="header-anchor" href="#fileasset-version" aria-label="Permalink to &quot;FileAsset@version&quot;">​</a></h3><p>Optional immutable file blobs used by bundles.</p><p>Fields:</p><ul><li><code>fileRef</code></li><li><code>path</code></li><li><code>contentDigest</code></li><li><code>contentLocation</code></li></ul><h3 id="policy-version" tabindex="-1">Policy@version <a class="header-anchor" href="#policy-version" aria-label="Permalink to &quot;Policy@version&quot;">​</a></h3><p>Immutable policy package.</p><p>Fields:</p><ul><li><code>policyRef</code></li><li><code>rules</code></li><li><code>enforcementMode</code></li></ul><h3 id="bundle-version" tabindex="-1">Bundle@version <a class="header-anchor" href="#bundle-version" aria-label="Permalink to &quot;Bundle@version&quot;">​</a></h3><p>Deployable immutable unit.</p><p>Fields:</p><ul><li><code>bundleRef</code> (<code>bundle:&lt;scope&gt;:&lt;version&gt;</code>)</li><li><code>scope</code></li><li><code>schemaRef</code></li><li><code>templateRef</code></li><li><code>valuesRef</code></li><li><code>fileRefs[]</code></li><li><code>policyRefs[]</code></li><li><code>lockedBindings</code></li><li><code>digest</code></li><li><code>signature</code> (optional or required by scope policy)</li><li><code>createdAt</code>, <code>createdBy</code></li></ul><h3 id="runrecord" tabindex="-1">RunRecord <a class="header-anchor" href="#runrecord" aria-label="Permalink to &quot;RunRecord&quot;">​</a></h3><p>Execution record linked to bundle digest.</p><p>Fields:</p><ul><li><code>runId</code></li><li><code>scope</code></li><li><code>bundleRef</code></li><li><code>bundleDigest</code></li><li><code>mode</code> (<code>local</code>, <code>remote</code>, <code>offline</code>)</li><li><code>actor</code></li><li><code>startedAt</code>, <code>completedAt</code></li><li><code>result</code> (<code>success</code>, <code>failure</code>, <code>partial</code>)</li><li><code>outputArtifacts[]</code></li></ul><h2 id="lifecycle-and-state-transitions" tabindex="-1">Lifecycle and State Transitions <a class="header-anchor" href="#lifecycle-and-state-transitions" aria-label="Permalink to &quot;Lifecycle and State Transitions&quot;">​</a></h2><ol><li>Publish immutable objects (<code>Schema</code>, <code>Template</code>, <code>Values</code>, optional <code>FileAsset</code>, <code>Policy</code>).</li><li>Create pinned immutable <code>Bundle</code> from exact references.</li><li>Promote bundle reference across environment refs (<code>dev/stable</code>, <code>prod/stable</code>).</li><li>Execute runs against pinned bundle.</li><li>Track drift and emit findings.</li></ol><h2 id="api-surface-core" tabindex="-1">API Surface (Core) <a class="header-anchor" href="#api-surface-core" aria-label="Permalink to &quot;API Surface (Core)&quot;">​</a></h2><ul><li><code>POST /v1/projects</code></li><li><code>POST /v1/environments</code></li><li><code>POST /v1/schemas</code></li><li><code>POST /v1/templates</code></li><li><code>POST /v1/values</code></li><li><code>POST /v1/files</code></li><li><code>POST /v1/policies</code></li><li><code>POST /v1/bundles</code></li><li><code>POST /v1/promotions</code></li><li><code>POST /v1/runs</code></li><li><code>GET /v1/runs/{runId}</code></li></ul><h2 id="required-invariants" tabindex="-1">Required Invariants <a class="header-anchor" href="#required-invariants" aria-label="Permalink to &quot;Required Invariants&quot;">​</a></h2><ul><li>Published versions are immutable.</li><li><code>Bundle</code> references immutable versions only.</li><li>Protected references cannot move without policy approval.</li><li>Every run references exact bundle digest.</li></ul><h2 id="promotion-model" tabindex="-1">Promotion Model <a class="header-anchor" href="#promotion-model" aria-label="Permalink to &quot;Promotion Model&quot;">​</a></h2><p>Reference aliases are mutable pointers with guardrails.</p><p>Examples:</p><ul><li><code>platform/payments/dev/stable -&gt; bundle:...:v21</code></li><li><code>platform/payments/prod/stable -&gt; bundle:...:v20</code></li></ul><p>Promotion updates pointer only after:</p><ul><li>approval checks</li><li>policy checks</li><li>compatibility checks</li></ul><h2 id="configuration-resolution-order" tabindex="-1">Configuration Resolution Order <a class="header-anchor" href="#configuration-resolution-order" aria-label="Permalink to &quot;Configuration Resolution Order&quot;">​</a></h2><p>For bundle execution:</p><ol><li>Bundle pinned references</li><li>Runtime overrides permitted by policy</li><li>External provider values (if configured)</li><li>Fallback defaults</li></ol><p>Any override must be reflected in provenance output.</p><h2 id="cli-control-plane-core" tabindex="-1">CLI (Control Plane Core) <a class="header-anchor" href="#cli-control-plane-core" aria-label="Permalink to &quot;CLI (Control Plane Core)&quot;">​</a></h2><ul><li><code>konfigo login</code></li><li><code>konfigo project create ...</code></li><li><code>konfigo env create ...</code></li><li><code>konfigo push schema ...</code></li><li><code>konfigo push template ...</code></li><li><code>konfigo push values ...</code></li><li><code>konfigo push file ...</code></li><li><code>konfigo push policy ...</code></li><li><code>konfigo bundle create --pin ...</code></li><li><code>konfigo promote ...</code></li><li><code>konfigo run --server ... --bundle ...</code></li></ul><h2 id="security-baseline" tabindex="-1">Security Baseline <a class="header-anchor" href="#security-baseline" aria-label="Permalink to &quot;Security Baseline&quot;">​</a></h2><ul><li>OIDC-based human auth</li><li>workload identity for CI/CD</li><li>short-lived scoped tokens</li><li>scope-prefix RBAC/ABAC</li><li>full audit logging</li></ul><h2 id="data-retention" tabindex="-1">Data Retention <a class="header-anchor" href="#data-retention" aria-label="Permalink to &quot;Data Retention&quot;">​</a></h2><ul><li>immutable objects: retained by policy (default long-term)</li><li>run records: hot 90 days, archive configurable</li><li>promotion history: long-term</li></ul><h2 id="observability" tabindex="-1">Observability <a class="header-anchor" href="#observability" aria-label="Permalink to &quot;Observability&quot;">​</a></h2><ul><li>object publish counts and latency</li><li>promotion success/failure counts</li><li>run success/failure by scope</li><li>policy denial counts</li></ul><h2 id="rollout-plan" tabindex="-1">Rollout Plan <a class="header-anchor" href="#rollout-plan" aria-label="Permalink to &quot;Rollout Plan&quot;">​</a></h2><h3 id="phase-1" tabindex="-1">Phase 1 <a class="header-anchor" href="#phase-1" aria-label="Permalink to &quot;Phase 1&quot;">​</a></h3><ul><li>Core immutable model and bundle creation</li><li>Run record persistence</li></ul><h3 id="phase-2" tabindex="-1">Phase 2 <a class="header-anchor" href="#phase-2" aria-label="Permalink to &quot;Phase 2&quot;">​</a></h3><ul><li>Promotion refs with approval gates</li><li>file assets and policy bundles</li></ul><h3 id="phase-3" tabindex="-1">Phase 3 <a class="header-anchor" href="#phase-3" aria-label="Permalink to &quot;Phase 3&quot;">​</a></h3><ul><li>advanced compatibility checks and signed bundle enforcement by policy</li></ul>',82)]))}const m=o(c,[["render",t]]);export{h as __pageData,m as default};
